parameters.jsCode:
// === STEP 1: Try parse Gemini response (graceful failure) ===
let aiVerdict = {};
let geminiSuccess = false;

try {
  const rawText = $input.first().json.candidates[0].content.parts[0].text;

  function sanitizeJson(str) {
    return str
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
      .trim();
  }

  const cleanText = sanitizeJson(rawText);

  try {
    aiVerdict = JSON.parse(cleanText);
    geminiSuccess = true;
  } catch (err) {
    const match = cleanText.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        aiVerdict = JSON.parse(match[0]);
        geminiSuccess = true;
      } catch (e) {
        aiVerdict = {};
      }
    }
  }
} catch (e) {
  // Gemini quota exceeded / network error / no response
  aiVerdict = {};
  geminiSuccess = false;
}

// === STEP 2: Get webhook data ===
const webhookData = $('Webhook').item.json.body;
const score = Number(webhookData.abuseScore) || 0;
const isp = webhookData.isp || '';
const country = webhookData.country || '';

// === STEP 3: DETERMINISTIC LOGIC (always reliable) ===
let finalRiskLevel, finalAction;

if (score >= 90) {
  finalRiskLevel = 'CRITICAL';
  finalAction = 'BLOCK';
} else if (score >= 70) {
  finalRiskLevel = 'HIGH';
  finalAction = 'BLOCK';
} else if (score >= 40) {
  finalRiskLevel = 'MEDIUM';
  finalAction = 'MONITOR';
} else if (score >= 10) {
  finalRiskLevel = 'LOW';
  finalAction = 'MONITOR';
} else {
  finalRiskLevel = 'LOW';
  finalAction = 'ALLOW';
}

// Override: reputable ISP whitelist
const reputableISPs = ['Google', 'Cloudflare', 'Amazon', 'Microsoft', 'Apple', 'AWS'];
const isReputable = reputableISPs.some(name => isp.toLowerCase().includes(name.toLowerCase()));
if (score === 0 && isReputable) {
  finalRiskLevel = 'LOW';
  finalAction = 'ALLOW';
}

// Override: high risk countries
const highRiskCountries = ['Russia', 'China', 'Iran', 'North Korea'];
if (highRiskCountries.includes(country) && score >= 40 && finalRiskLevel === 'MEDIUM') {
  finalRiskLevel = 'HIGH';
  finalAction = 'BLOCK';
}

// === STEP 4: Validate & sanitize Gemini output ===
const isCorruptedByTemplate = (str) => {
  if (typeof str !== 'string') return true;
  return str.includes('{{') || str.includes('}}');
};

// Generate fallback threat_type
let fallbackThreatType;
if (finalRiskLevel === 'CRITICAL') fallbackThreatType = 'Malicious Activity';
else if (finalRiskLevel === 'HIGH') fallbackThreatType = 'Suspicious Activity';
else if (finalRiskLevel === 'MEDIUM') fallbackThreatType = 'Potentially Risky';
else fallbackThreatType = 'Benign Traffic';

// Generate fallback explanation
const fallbackExplanation = `AbuseIPDB score ${score}/100 from ${isp} in ${country}. Classified as ${finalRiskLevel} risk. Recommended action: ${finalAction}.`;

// Use Gemini values if valid, else fallback
const safeThreatType = (geminiSuccess && !isCorruptedByTemplate(aiVerdict.threat_type) && aiVerdict.threat_type)
  ? aiVerdict.threat_type
  : fallbackThreatType;

const safeExplanation = (geminiSuccess && !isCorruptedByTemplate(aiVerdict.explanation) && aiVerdict.explanation)
  ? aiVerdict.explanation
  : fallbackExplanation;

// === STEP 5: Final output ===
return [
  {
    json: {
      ip: webhookData.ip,
      country: country,
      isp: isp,
      abuseScore: score,
      action: webhookData.action,
      ai_risk_level: finalRiskLevel,           // deterministic (selalu akurat)
      ai_threat_type: safeThreatType,          // Gemini OR fallback
      ai_recommended_action: finalAction,      // deterministic
      ai_explanation: safeExplanation,         // Gemini OR fallback
      ai_analyzed_at: new Date().toISOString(),
      ai_source: geminiSuccess ? 'gemini' : 'rule-based'  // bonus: track source
    }
  }
];

